    .replace(/\u0436/g, "zh")
    .replace(/\u0445/g, "kh")
    .replace(/\u0446/g, "ts")
    .replace(/\u044e/g, "iu")
    .replace(/\u044f/g, "ia")
    .replace(/\u0454/g, "ie")
    .replace(/\u0457/g, "i")
    .replace(/\u0456/g, "i")
