function parseOne(input) {
  const messageText = input.message?.text;

  if (!messageText) {
    return fail(input, "Missing message.text with question JSON.");
  }

  let payload;

  try {
    payload = JSON.parse(messageText);
  } catch (error) {
    return fail(input, "message.text is not valid JSON.");
  }

  const allowedCategories = [
    "erudite",
    "science",
    "philosophy",
    "culture",
    "noesis",
    "agora"
  ];

  const allowedTypes = [
    "SINGLE_CHOICE",
    "MULTIPLE_CHOICE",
    "TRUE_FALSE",
    "SEQUENCE",
    "MATCHING",
    "COMPARISON",
    "TEXT_INPUT",
    "FILL_IN_THE_BLANK",
    "IMAGE_CHOICE",
    "READING_COMPREHENSION",
    "SLIDER_SCALE",
    "TEN_FACTS"
  ];

  const categoryId = payload.categoryId || input.generationOptions?.categoryId;
  const levelId = String(payload.levelId || input.generationOptions?.levelId || "");
  const rawNum = payload.num ?? input.generationOptions?.num ?? 1;
  const num = Number(rawNum);
  const block = String(payload.block || input.generationOptions?.block || "").toUpperCase();
  const rawSlug = payload.slug;
  const data = payload.data;

  if (!allowedCategories.includes(categoryId)) {
    return fail(input, "Invalid categoryId.");
  }

  if (!levelId) {
    return fail(input, "Missing levelId.");
  }

  if (!Number.isInteger(num) || num < 1 || num > 999) {
    return fail(input, "num must be an integer from 1 to 999.");
  }

  if (!/^[A-Z]$/.test(block)) {
    return fail(input, "block must be one uppercase letter.");
  }

  if (!data || typeof data !== "object") {
    return fail(input, "Missing data object.");
  }

  if (data.lang !== "ua") {
    return fail(input, "data.lang must be ua.");
  }

  if (!allowedTypes.includes(data.type)) {
    return fail(input, "Invalid question type.");
  }

  if (!Array.isArray(data.topics) || data.topics.length === 0) {
    return fail(input, "data.topics must be a non-empty array.");
  }

  if (!data.question && !["READING_COMPREHENSION", "SLIDER_SCALE"].includes(data.type)) {
    return fail(input, "data.question is required for this question type.");
  }

  if (Array.isArray(data.correctAnswerIndices)) {
    data.correctAnswerIndices = data.correctAnswerIndices.map(Number);
  }

  if (data.type === "SINGLE_CHOICE") {
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail(input, "SINGLE_CHOICE must have exactly 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail(input, "SINGLE_CHOICE must have exactly one correctAnswerIndices item.");
    }
  }

  if (data.type === "MULTIPLE_CHOICE") {
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail(input, "MULTIPLE_CHOICE must have exactly 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length < 2) {
      return fail(input, "MULTIPLE_CHOICE must have at least two correct indices.");
    }
  }

  if (data.type === "TRUE_FALSE" && typeof data.correctAnswer !== "boolean") {
    return fail(input, "TRUE_FALSE must have boolean correctAnswer.");
  }

  const numPart = String(num).padStart(2, "0");
  const slug = slugify(rawSlug || data.question || data.type);
  const questionId = `${data.lang}--${numPart}--${block}--${slug}--${randomId()}`;
  const now = new Date().toISOString();

  const documentData = {
    ...data,
    categoryId,
    levelId,
    questionId,
    num,
    block,
    slug,
    status: "pending_review",
    source: "telegram-n8n-ai-quiz",
    createdAt: now,
    updatedAt: now
  };

  const previewText = [
    "New question for moderation",
    "",
    `Category: ${categoryId}`,
    `Level: ${levelId}`,
    `Block: ${block}`,
    `Type: ${data.type}`,
    `ID: ${questionId}`,
    `Topics: ${data.topics.join(", ")}`,
    "",
    "Question:",
    data.question || data.text || "No short question text",
    "",
    "Answers:",
    formatAnswerPreview(data),
    "",
    data.explanation ? `Explanation:\n${data.explanation}` : "Explanation: missing",
    "",
    "Actions:",
    "approve / reject / revise"
  ].join("\n");

  return {
    json: {
      valid: true,
      categoryId,
      levelId,
      questionId,
      collectionPath: `${categoryId}/${levelId}/questions`,
      levelDocumentPath: `${categoryId}/${levelId}`,
      pendingCollectionPath: "pendingQuestions",
      documentData,
      previewText,
      telegramChatId: input.message.chat.id,
      telegramFromId: input.message.from.id,
      originalTelegramMessageId: input.message.message_id,
      generationOptions: input.generationOptions || null
    }
  };
}

