if (typeof input.sourceConfidence === "number") {
  sourceConfidence = input.sourceConfidence;
} else if (input.sourceConfidence !== undefined && input.sourceConfidence !== null) {
  const parsed = Number(input.sourceConfidence);
  sourceConfidence = Number.isFinite(parsed) ? parsed : null;
