function norm(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "");
}

function hasAny(text, patterns) {
  return patterns.some((pattern) => text.includes(pattern));
}

const topic = norm(item.topic);
const categoryId = norm(item.categoryId);

function detectDiscipline(topic, categoryId) {
  const topicLatin = topic
    .replace(/ї/g, "i")
    .replace(/і/g, "i")
    .replace(/є/g, "e")
    .replace(/ґ/g, "g");

  if (
    hasAny(topicLatin, [
      "astronom",
      "kosmos",
      "planet",
      "zor",
      "galakt",
      "teleskop",
      "soniach",
      "sonyach",
      "misiats",
      "misyac",
      "mars",
      "yupiter",
      "jupiter",
      "ekzoplanet"
    ])
  ) {
    return "astronomy";
  }

  if (
    hasAny(topicLatin, [
      "filosof",
      "aristotel",
      "platon",
      "kant",
      "hegel",
      "nitsshe",
      "nietzsche",
      "etyk",
      "etik",
      "metafiz",
      "epistemolog"
    ]) ||
    categoryId === "philosophy"
  ) {
    return "philosophy";
  }

  if (
    hasAny(topicLatin, [
      "kyivska rus",
      "kiivska rus",
      "kievan rus",
      "kyivan rus",
      "rus",
      "serednovich",
      "kniaz",
      "knyaz",
      "litopys",
      "istor"
    ]) ||
    categoryId === "culture" ||
    categoryId === "erudite"
  ) {
    return "history";
  }

  if (
    hasAny(topicLatin, [
      "medyts",
      "medic",
      "biolog",
      "psykholog",
      "psycholog",
      "epidem",
      "klinich",
      "zdorov"
    ])
  ) {
    return "biomedicine";
  }

  if (
    hasAny(topicLatin, [
      "matemat",
      "fizyk",
      "fizik",
      "algorytm",
      "algorithm",
      "shtuchn",
      "statyst",
      "statist",
      "ai",
      "machine learning"
    ]) ||
    categoryId === "science"
  ) {
    return "science";
  }

  return "general";
}

