    strongSourceTypes: ["systematic_review", "clinical_guideline", "peer_reviewed_article", "official_health_agency"],
    allowOfficialSingleSource: false,
    allowCuratedSingleSource: false,
    preprintsAllowed: false,
    requiresReview: true,
    quotePolicy: "short_excerpt_only"
  },

  science: {
    discipline: "science",
    minSources: 2,
    preferredProviderOrder: ["openalex", "crossref", "arxiv"],
    preferredDomains: [
      "nature.com",
      "science.org",
      "springer.com",
      "sciencedirect.com",
      "arxiv.org",
      "openalex.org"
    ],
    strongSourceTypes: ["peer_reviewed_article", "official_agency", "academic_reference"],
    allowOfficialSingleSource: true,
    allowCuratedSingleSource: true,
    quotePolicy: "short_excerpt_or_public_domain_only"
  },

  general: {
    discipline: "general",
    minSources: 2,
    preferredProviderOrder: ["curated", "openalex", "crossref"],
    preferredDomains: [
      "openalex.org",
      "britannica.com",
      "encyclopedia.com",
      "wikisource.org",
      "gutenberg.org"
    ],
    strongSourceTypes: ["curated_reference", "peer_reviewed_article", "academic_reference", "official_source"],
    allowOfficialSingleSource: true,
    allowCuratedSingleSource: true,
    quotePolicy: "short_excerpt_or_public_domain_only"
  }
};

const sourcePolicy = {
  ...(policies[discipline] || policies.general),
  rejectSourceTypes: [
    "content_farm",
    "seo_blog",
    "ai_generated_page",
    "unsourced_wiki_copy",
    "forum_post",
    "social_media_post"
  ],
  sufficiencyRules: {
    insufficientIfNoSources: true,
    insufficientIfNoDirectSupport: true,
    weakIfOnlyOneNonCuratedSource: true,
    minimumConfidenceForOk: 0.65,
    minimumConfidenceForWeak: 0.45
  }
};

return [
  {
    json: {
      ...item,
      sourcePolicy
    }
  }
];

const input = $input.item.json;

const sourceBriefQuality = input.sourceBriefQuality || "none";
const sourceBriefStatus = input.sourceBriefStatus || "none";
const sourceConfidence = Number(input.sourceConfidence ?? 0);

const sourceAuthoritySummary = input.sourceAuthoritySummary || {};
const sourcePolicy = input.sourcePolicy || {};

const saveToDb = input.saveToDb === true;
const researchEnabled = input.researchEnabled === true;

const totalSources = Number(sourceAuthoritySummary.totalSources || 0);
const strongSources = Number(sourceAuthoritySummary.strongSources || 0);
const minSources = Number(sourceAuthoritySummary.minSources || sourcePolicy.minSources || 2);
const hasCurated = sourceAuthoritySummary.hasCurated === true;

const isInsufficient =
  sourceBriefQuality === "insufficient" ||
  sourceBriefStatus === "insufficient_sources" ||
  totalSources === 0 ||
  sourceConfidence < 0.45;

const isWeak =
  sourceBriefQuality === "weak" ||
  sourceBriefStatus === "weak" ||
  sourceConfidence < 0.65 ||
  strongSources < minSources;

const sufficientForDraft =
  !researchEnabled ||
  !isInsufficient ||
  hasCurated;

const sufficientForDb =
  !researchEnabled ||
  (
    !isInsufficient &&
    !isWeak &&
    sourceConfidence >= 0.65 &&
    (strongSources >= minSources || hasCurated)
  );

let reason = "source_sufficient";

if (researchEnabled && isInsufficient && saveToDb) {
  reason = "insufficient_sources_for_db";
} else if (researchEnabled && isInsufficient) {
  reason = "insufficient_sources_for_draft_with_review";
} else if (researchEnabled && isWeak && saveToDb) {
  reason = "weak_sources_for_db";
} else if (researchEnabled && isWeak) {
  reason = "weak_sources_for_draft_with_review";
}

return [
  {
    json: {
      ...input,
      sourceSufficiency: {
        sufficientForDraft,
        sufficientForDb,
        reason,
        researchEnabled,
        saveToDb,
        sourceBriefQuality,
        sourceBriefStatus,
        sourceConfidence,
        totalSources,
        strongSources,
        minSources,
        hasCurated,
        discipline: sourcePolicy.discipline || null
      }
    }
  }
];

const input = $input.item.json;

function normalize(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}]+/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const keyParts = {
  topic: normalize(input.topic),
  searchQuery: normalize(input.searchQuery),
  categoryId: input.categoryId || null,
  levelId: String(input.levelId || ""),
  researchProvider: input.researchProvider || "openalex",
  sourceLimit: Number(input.sourceLimit || 3),
  sourcePolicyDiscipline: input.sourcePolicy?.discipline || null,
  version: "sourcebrief-v1"
};

const rawKey = JSON.stringify(keyParts);

let hash = 0;
for (let i = 0; i < rawKey.length; i++) {
  hash = ((hash << 5) - hash) + rawKey.charCodeAt(i);
  hash |= 0;
}

const sourceBriefCacheKey = `sb_${Math.abs(hash).toString(36)}`;

return [
  {
    json: {
      ...input,
      sourceBriefCacheKey,
      sourceBriefCacheKeyParts: keyParts
    }
  }
];

const cached = $input.item.json;

return [
  {
    json: {
      ...$("Build Source Cache Key").item.json,

      sourceBrief: cached.sourceBrief,
      sourceBriefStatus: cached.sourceBriefStatus,
      sourceBriefQuality: cached.sourceBriefQuality,
      sourceConfidence: cached.sourceConfidence,

      curatedSources: cached.curatedSources || [],
      retrievedSources: cached.retrievedSources || [],
      sourceAuthoritySummary: cached.sourceAuthoritySummary || null,
      sourcePolicy: cached.sourcePolicy || $("Build Source Cache Key").item.json.sourcePolicy || null,

      sourceBriefCacheKey: cached.sourceBriefCacheKey || $("Build Source Cache Key").item.json.sourceBriefCacheKey,
      sourceBriefCacheHit: true,
      sourceBriefCachedAt: cached.cachedAt || null
    }
  }
];

const original = $("Build Source Cache Key").item.json;

return [
  {
    json: {
      ...original,
      sourceBriefCacheHit: false
    }
  }
];

const input = $input.item.json;

const now = new Date();
const expiresAt = new Date(now.getTime() + 14 * 24 * 60 * 60 * 1000);

return [
  {
    json: {
      sourceBriefCacheKey: input.sourceBriefCacheKey,
      sourceBriefCacheKeyParts: input.sourceBriefCacheKeyParts,

      sourceBrief: input.sourceBrief,
      sourceBriefStatus: input.sourceBriefStatus,
      sourceBriefQuality: input.sourceBriefQuality,
      sourceConfidence: input.sourceConfidence,

      sourceAuthoritySummary: input.sourceAuthoritySummary || null,
      sourcePolicy: input.sourcePolicy || null,

      curatedSources: input.curatedSources || [],
      retrievedSources: input.retrievedSources || [],

      cachedAt: now.toISOString(),
      expiresAt: expiresAt.toISOString(),

      cacheVersion: "sourcebrief-v1"
    }
  }
];

return [
  {
    json: {
      ...$("Build Source Brief").item.json,
      sourceBriefCacheHit: false,
      sourceBriefCachedNow: true
    }
  }
];

const input = $input.item.json;

function toSearchText(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "");
}

function translitUk(value) {
  return toSearchText(value)
    .replace(/\u0449/g, "shch")
    .replace(/\u0448/g, "sh")
    .replace(/\u0447/g, "ch")
    .replace(/\u0436/g, "zh")
    .replace(/\u0445/g, "kh")
    .replace(/\u0446/g, "ts")
    .replace(/\u044e/g, "iu")
    .replace(/\u044f/g, "ia")
    .replace(/\u0454/g, "ie")
    .replace(/\u0457/g, "i")
    .replace(/\u0456/g, "i")
    .replace(/\u0491/g, "g")
    .replace(/\u0439/g, "i")
    .replace(/\u0430/g, "a")
    .replace(/\u0431/g, "b")
    .replace(/\u0432/g, "v")
    .replace(/\u0433/g, "h")
    .replace(/\u0434/g, "d")
    .replace(/\u0435/g, "e")
    .replace(/\u0437/g, "z")
    .replace(/\u0438/g, "y")
    .replace(/\u043a/g, "k")
    .replace(/\u043b/g, "l")
    .replace(/\u043c/g, "m")
    .replace(/\u043d/g, "n")
    .replace(/\u043e/g, "o")
    .replace(/\u043f/g, "p")
    .replace(/\u0440/g, "r")
    .replace(/\u0441/g, "s")
    .replace(/\u0442/g, "t")
    .replace(/\u0443/g, "u")
    .replace(/\u0444/g, "f")
    .replace(/\u044c/g, "");
}

function normalizeKeyText(value) {
  return translitUk(value)
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function slugify(value) {
  return normalizeKeyText(value)
    .replace(/\s+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

const topicKeyText = normalizeKeyText(input.topic);
const discipline = input.sourcePolicy?.discipline || "general";

let curatedSourceSetKey = `${discipline}__${slugify(input.topic)}`;

const aliases = [
  {
    key: "history__kyivska-rus",
    discipline: "history",
    keywords: [
      "kyivska rus",
      "kiivska rus",
      "kyivan rus",
      "kievan rus"
    ]
  }
];

const matched = aliases.find((entry) => {
  if (entry.discipline && entry.discipline !== discipline) {
    return false;
  }

  return entry.keywords.some((keyword) => {
    return topicKeyText.includes(normalizeKeyText(keyword));
  });
});

if (matched) {
  curatedSourceSetKey = matched.key;
}

return [
  {
    json: {
      ...input,
      curatedSourceSetKey,
      curatedSourceSetLookup: {
        topic: input.topic,
        normalizedTopic: topicKeyText,
        discipline,
        matchedAlias: matched?.key || null
      }
    }
  }
];

