const original = $("Load Curated Sources").item.json;
const searchResponse = $input.item.json || {};

const hasOpenAlexError =
  Boolean(searchResponse.error) ||
  Boolean(searchResponse.errorMessage) ||
  Boolean(searchResponse.message && !Array.isArray(searchResponse.results));

const results = Array.isArray(searchResponse.results)
  ? searchResponse.results
  : [];

return [
  {
    json: {
      ...original,
      openAlexResponse: searchResponse,
      openAlexAvailable: !hasOpenAlexError,
      openAlexError: hasOpenAlexError
        ? {
            error: searchResponse.error || null,
            errorMessage: searchResponse.errorMessage || searchResponse.message || "OpenAlex request failed.",
            httpCode: searchResponse.httpCode || searchResponse.statusCode || null
          }
        : null,
      results
    }
  }
];

const pending = $input.first().json;
const callback = $("Parse Callback").item.json;
const action = callback.action;

const currentStatus = pending.status || "unknown";

const allowedStatusesByAction = {
  approve: ["pending_review", "needs_revision"],
  revise: ["pending_review"],
  reject: ["pending_review", "needs_revision"]
};

const allowedStatuses = allowedStatusesByAction[action] || [];
const isActionable = allowedStatuses.includes(currentStatus);

return [
  {
    json: {
      ...pending,
      callbackAction: action,
      callbackQuestionId: callback.questionId,
      callbackTelegramChatId: callback.telegramChatId,
      callbackTelegramMessageId: callback.telegramMessageId,
      callbackQueryId: callback.callbackQueryId,
      isActionable,
      currentStatus,
      blockedReason: isActionable
        ? null
        : `Question has already been processed or cannot be changed from status: ${currentStatus}`
    }
  }
];

const pending = $input.item.json;

const now = new Date().toISOString();

return [
  {
    json: {
      ...pending,
      status: "rejected",
      rejectedAt: now,
      updatedAt: now
    }
  }
];

